"""Activity: Union Dissector

Complete a C++ program that uses a union to inspect raw bit patterns. Learn why union type-punning is defined in C but undefined behavior in C++, and what the safe C++ alternatives are.
"""
import os, shutil, subprocess, sys, tempfile, zipfile

# -- Crypto / obfuscation --
import hashlib as _hl, hmac as _hm

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000
_BLOB      = "dcc7fc663784f1e6d16819f06a535e0683baf54657c9718f11664551ac46ef4efe2a7264f3195ea6f6014c3ed2c5626438d967a90bbe0fd04f"

def _decrypt(key_str):
    key  = _hl.pbkdf2_hmac("sha256", key_str.encode(), _SALT, _KDF_ITERS)
    blob = bytes.fromhex(_BLOB)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    ks, i, stream = b"", 0, b""
    while len(stream) < len(ct):
        stream += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return bytes(a ^ b for a, b in zip(ct, stream)).decode()

# -- Helpers --
import textwrap as _tw

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _wrap(text):
    return _tw.wrap(text, width=_LINE_WIDTH - 4,
                    initial_indent="  ", subsequent_indent="    ")

def _show_wrong(raw, wrong_dict):
    exp = wrong_dict.get(raw)
    if exp:
        print()
        for ln in _wrap(f"[wrong] {exp}"):
            print(ln)
    else:
        print(f"  [wrong] {raw!r} is not the correct answer.")

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)

def _compile_run(src, name, repo_dir):
    binary = os.path.join(repo_dir, name)
    r = subprocess.run(
        ["g++", "-std=c++17", "-o", binary, os.path.join(repo_dir, src)],
        capture_output=True, text=True,
    )
    if r.returncode != 0:
        return None, r.stderr
    try:
        run = subprocess.run([binary], capture_output=True, text=True, timeout=10)
    except subprocess.TimeoutExpired:
        return None, "timeout"
    return run.stdout.strip(), None

def _make_build(repo_dir):
    r = subprocess.run(["make"], capture_output=True, text=True, cwd=repo_dir)
    return r.returncode == 0, r.stderr

def _run_binary(repo_dir, name, timeout=10):
    exe = os.path.join(repo_dir, name)
    if not os.path.isfile(exe):
        return None, f"{name} binary not found -- did the build succeed?"
    try:
        r = subprocess.run([exe], capture_output=True, text=True, timeout=timeout, cwd=repo_dir)
        return r.stdout.strip(), None
    except subprocess.TimeoutExpired:
        return None, "timeout"
    except Exception as e:
        return None, str(e)

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

def _extract_repo():
    if not os.path.isfile(REPO_ZIP):
        die("repo.zip not found.")
    work_dir = tempfile.mkdtemp(prefix="union-dissector-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die("unexpected zip structure")
    return work_dir, os.path.join(work_dir, entries[0])

def _make_rcfile(repo_dir):
    banner_text = """
      ============================================================
       Activity: Union Dissector
      ============================================================

       A C++ program with four TODOs.  Your job: fill them in, build, and run.
       
       NOTE: In C, union type-punning (reading a member you did not write) is
       defined behavior (C11 6.5.2.3).  In C++, it is technically undefined
       behavior.  GCC and Clang support it as an extension.  The safe C++
       alternatives are std::memcpy (C++11) and std::bit_cast<T> (C++20).
       The README explains when to use each approach.
       
       Step 1 -- read the starter file to understand the union definition
         cat union_lab.cpp
       
       Step 2 -- fill in TODO 1 (store 0x3F800000, read back as float)
         Open union_lab.cpp in your editor and complete the first TODO block.
         Expected output line: as_float: 1
       
       Step 3 -- fill in TODO 2 (print all 4 bytes as hex)
         Loop over bv.bytes[0..3] and print each as a 2-digit hex number.
         Expected output line: bytes: 00 00 80 3f
       
       Step 4 -- fill in TODO 3 (store -0.0f, read back as uint hex)
         Expected output line: neg_zero_bits: 80000000
       
       Step 5 -- fill in TODO 4 (print sizeof the union)
         Expected output line: sizeof(ByteView): 4
       
       Step 6 -- build and run
         make
         ./union_lab
       
       When the output matches all four expected lines, type 'exit'.
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        f'PS1=\'\\u@union-dissector:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << 'BANNER'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()
    return rcfile

def _drop_to_shell(repo_dir):
    rcfile = _make_rcfile(repo_dir)
    shell = os.environ.get("SHELL", "/bin/bash")
    try:
        subprocess.run([shell, "--rcfile", rcfile.name])
    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass

def run_shell_drop_once():
    work_dir, repo_dir = _extract_repo()
    _drop_to_shell(repo_dir)
    return repo_dir, work_dir

def run_shell_drop_with_retry(is_ready, not_ready_lines):
    work_dir, repo_dir = _extract_repo()
    while True:
        _drop_to_shell(repo_dir)
        if is_ready(repo_dir):
            return repo_dir, work_dir
        print()
        for line in not_ready_lines(repo_dir):
            print(line)
        print()
        try:
            again = input("  Try again? [y/n] ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print()
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None
        if again != "y":
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None

def run_shell_drop_validated(check):
    work_dir, repo_dir = _extract_repo()
    try:
        while True:
            _drop_to_shell(repo_dir)
            print()
            _banner("Activity: Union Dissector -- Checking Your Work")
            print()
            passphrase, feedback = check(repo_dir)
            if passphrase is not None:
                _show_passphrase(passphrase)
                return True
            for line in feedback:
                print(line)
            print()
            try:
                again = input("  Try again? [y/n] ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                return False
            if again != "y":
                return False
            print()
    finally:
        shutil.rmtree(work_dir, ignore_errors=True)

class ActivityEngine:
    """Core build/run/validate logic for Activity: Union Dissector; importable without a TTY."""

    slug = "union-dissector"
    title = "Activity: Union Dissector"
    description = 'Complete a C++ program that uses a union to inspect raw bit patterns. Learn why union type-punning is defined in C but undefined behavior in C++, and what the safe C++ alternatives are.'

    def _check(self, repo_dir):
        build_ok, build_err = _make_build(repo_dir)
        if not build_ok:
            lines = ["  make failed.  Fix the compilation errors first."]
            lines += [f"    {ln}" for ln in build_err.strip().splitlines()[:10]]
            return None, lines
        output, err = _run_binary(repo_dir, "union_lab")
        if output is None:
            return None, [f"  union_lab did not run: {err}"]
        passphrase = _decrypt(output)
        if passphrase is not None:
            return passphrase, []
        lines = [
            "  union_lab ran but the output did not match the expected lines.",
            "  Check each TODO: the exact format of each printf line matters.",
            "",
            "  Your output was:",
        ]
        lines += [f"    {ln}" for ln in output.splitlines()]
        return None, lines


    def check(self, repo_dir):
        """Build+run the student's repo; return (passphrase_or_None, feedback_lines)."""
        return self._check(repo_dir)


ENGINE = ActivityEngine()


def main():
    _banner(ENGINE.title)
    print()
    input("  Press Enter to begin...")

    ok = run_shell_drop_validated(ENGINE.check)
    if not ok:
        sys.exit(0)


if __name__ == "__main__":
    main()
